using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains the ML.NET ticket classification model at startup
/// and writes the .zip model file for PredictionEnginePool to consume.
/// </summary>
public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly LabelService _labelService;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainerService(
        ILogger<ModelTrainerService> logger,
        LabelService labelService,
        IWebHostEnvironment env)
    {
        _logger = logger;
        _labelService = labelService;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns + numeric priority into a single Features vector
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Extract label ordering from the trained model's Score column
        var schema = model.Transform(split.TrainSet).Schema;
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        schema["Score"].GetSlotNames(ref labelBuffer);
        _labelService.Labels = labelBuffer.DenseValues()
            .Select(v => v.ToString()).ToArray();

        // Evaluate on the held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation(
            "Model evaluation — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);
        _logger.LogInformation("Per-class log-loss reduction: {Reduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("Confusion matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

